import { useState } from 'react';
import leadService from '../../services/leadService';

const inputClasses = "w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-gray-400 focus:border-transparent outline-none transition-all";
const labelClasses = "block text-sm font-medium text-gray-700 mb-2";

export default function LeadForm() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    company: '',
    status: '',
    turnover: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      await leadService.createLead(formData);
      setIsSuccess(true);
      setFormData({ name: '', email: '', phone: '', company: '', status: '', turnover: '' });
    } catch (err) {
      setError(err.message || 'Une erreur est survenue lors de l\'envoi du formulaire');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSuccess) {
    return (
      <section id="quote" className="py-16 bg-gray-50">
        <div className="max-w-lg mx-auto px-4">
          <div className="bg-white rounded-2xl shadow-xl p-8 text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h3 className="text-2xl font-bold text-gray-900 mb-2">Merci !</h3>
            <p className="text-gray-600 mb-4">
              Votre demande a été transmise. Un expert vous contactera sous 24h pour votre devis personnalisé d'assurance décennale.
            </p>
            <button onClick={() => setIsSuccess(false)} className="text-blue-800 font-medium hover:underline">
              Envoyer une autre demande
            </button>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section id="quote" className="py-16 bg-gray-50">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900">
            Obtenez votre <span className="text-blue-800">devis gratuit</span>
          </h2>
          <p className="mt-3 text-gray-600 text-lg">
            Remplissez le formulaire pour comparer les meilleures offres d'assurance décennale
          </p>
        </div>

        <div className="bg-white rounded-2xl shadow-xl p-6 md:p-10">
          {error && (
            <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700">
              {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <label htmlFor="name" className={labelClasses}>Nom complet *</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="Votre nom"
                />
              </div>
              <div>
                <label htmlFor="email" className={labelClasses}>Email *</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="votre@email.com"
                />
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <label htmlFor="phone" className={labelClasses}>Téléphone *</label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  required
                  value={formData.phone}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="06 12 34 56 78"
                />
              </div>
              <div>
                <label htmlFor="company" className={labelClasses}>Entreprise (optionnel)</label>
                <input
                  type="text"
                  id="company"
                  name="company"
                  value={formData.company}
                  onChange={handleChange}
                  className={inputClasses}
                  placeholder="Nom de votre société"
                />
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-6">
              <div>
                <label htmlFor="status" className={labelClasses}>Statut *</label>
                <select
                  id="status"
                  name="status"
                  required
                  value={formData.status}
                  onChange={handleChange}
                  className={inputClasses}
                >
                  <option value="">Sélectionner...</option>
                  <option value="auto-entrepreneur">Auto-entrepreneur</option>
                  <option value="artisan">Artisan</option>
                  <option value="sarl">SARL</option>
                  <option value="eurl">EURL</option>
                  <option value="sa">SA</option>
                  <option value="other">Autre</option>
                </select>
              </div>
              <div>
                <label htmlFor="turnover" className={labelClasses}>Chiffre d'affaires estimé</label>
                <select
                  id="turnover"
                  name="turnover"
                  value={formData.turnover}
                  onChange={handleChange}
                  className={inputClasses}
                >
                  <option value="">Sélectionner...</option>
                  <option value="0-30k">Moins de 30 000€</option>
                  <option value="30-60k">30 000€ - 60 000€</option>
                  <option value="60-100k">60 000€ - 100 000€</option>
                  <option value="100-250k">100 000€ - 250 000€</option>
                  <option value="250k+">Plus de 250 000€</option>
                </select>
              </div>
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full bg-gray-500 hover:bg-gray-600 text-white font-bold py-4 px-6 rounded-xl transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
            >
              {isSubmitting ? (
                <>
                  <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                  </svg>
                  Envoi en cours...
                </>
              ) : (
                'Obtenir mon devis'
              )}
            </button>

